#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');}
CI MAXN=1e6+5,MOD=1e4+7;ll a[MAXN],n,m,o[MAXN],x[MAXN],y[MAXN],f[MAXN],k;
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	cin>>n>>m>>k;
	for(int i=1,t;i<=k;++i)
	{
		cin>>t;
		++a[t];
		--a[t-1];
	}
	for(int i=1;i<=m;++i)
	{
		cin>>o[i]>>x[i]>>y[i];
	}
	ll w=0;
	for(int i=m;i;--i)
	{
		w+=a[i];
		if(o[i]==1)
		{
			f[x[i]]=(f[x[i]]+y[i]*w)%MOD;
		}
		else
		{
			a[x[i]-1]=((a[x[i]-1]-w)%MOD+MOD)%MOD;
			a[y[i]]=(a[y[i]]+w)%MOD;
		}
	}
	for(int i=1;i<=n;++i)
	{
		cout<<f[i]%MOD<<' ';
	}
	return false;
}
